ALTER TABLE `PrivateContentImport` ADD COLUMN `normalizedPayloadId` VARCHAR(191) NULL, ADD COLUMN `materializationStatus` VARCHAR(64) NOT NULL DEFAULT 'NOT_STARTED';
ALTER TABLE `PrivateAssetObject` ADD COLUMN `storageProvider` VARCHAR(64) NOT NULL DEFAULT 'local', ADD COLUMN `scanStatus` VARCHAR(32) NOT NULL DEFAULT 'PENDING', ADD COLUMN `quarantinedAt` DATETIME(3) NULL;
CREATE TABLE `PrivateContentOperation` (`id` VARCHAR(191) NOT NULL, `importId` VARCHAR(191) NULL, `ownerAccountId` VARCHAR(191) NULL, `kind` VARCHAR(64) NOT NULL, `state` VARCHAR(64) NOT NULL DEFAULT 'CREATED', `idempotencyKey` VARCHAR(191) NOT NULL, `correlationId` VARCHAR(191) NOT NULL, `progress` LONGTEXT NOT NULL, `cancelRequestedAt` DATETIME(3) NULL, `claimedAt` DATETIME(3) NULL, `claimOwner` VARCHAR(191) NULL, `claimExpiresAt` DATETIME(3) NULL, `failureCode` VARCHAR(191) NULL, `createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), `updatedAt` DATETIME(3) NOT NULL, PRIMARY KEY (`id`), UNIQUE KEY `PrivateContentOperation_idempotencyKey_key` (`idempotencyKey`), KEY `PrivateContentOperation_state_claimExpiresAt_idx` (`state`,`claimExpiresAt`), CONSTRAINT `PrivateContentOperation_importId_fkey` FOREIGN KEY (`importId`) REFERENCES `PrivateContentImport`(`id`) ON DELETE SET NULL, CONSTRAINT `PrivateContentOperation_ownerAccountId_fkey` FOREIGN KEY (`ownerAccountId`) REFERENCES `UserAccount`(`id`) ON DELETE SET NULL);
CREATE TABLE `PrivateContentUpload` (`id` VARCHAR(191) NOT NULL, `operationId` VARCHAR(191) NOT NULL, `storageProvider` VARCHAR(64) NOT NULL, `storageKey` VARCHAR(255) NOT NULL, `expectedSha256` CHAR(64) NULL, `receivedBytes` INTEGER NOT NULL DEFAULT 0, `expectedBytes` INTEGER NULL, `expiresAt` DATETIME(3) NOT NULL, `completedAt` DATETIME(3) NULL, `cancelledAt` DATETIME(3) NULL, `createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), `updatedAt` DATETIME(3) NOT NULL, PRIMARY KEY (`id`), UNIQUE KEY `PrivateContentUpload_operationId_key` (`operationId`), UNIQUE KEY `PrivateContentUpload_storageKey_key` (`storageKey`), KEY `PrivateContentUpload_expiresAt_completedAt_idx` (`expiresAt`,`completedAt`), CONSTRAINT `PrivateContentUpload_operationId_fkey` FOREIGN KEY (`operationId`) REFERENCES `PrivateContentOperation`(`id`) ON DELETE CASCADE);
CREATE TABLE `PrivateContentUploadPart` (`id` VARCHAR(191) NOT NULL, `uploadId` VARCHAR(191) NOT NULL, `partNumber` INTEGER NOT NULL, `sha256` CHAR(64) NOT NULL, `byteLength` INTEGER NOT NULL, `providerTag` VARCHAR(191) NULL, `createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), PRIMARY KEY (`id`), UNIQUE KEY `PrivateContentUploadPart_uploadId_partNumber_key` (`uploadId`,`partNumber`), CONSTRAINT `PrivateContentUploadPart_uploadId_fkey` FOREIGN KEY (`uploadId`) REFERENCES `PrivateContentUpload`(`id`) ON DELETE CASCADE);
CREATE TABLE `PrivateContentJob` (`id` VARCHAR(191) NOT NULL, `operationId` VARCHAR(191) NOT NULL, `type` VARCHAR(64) NOT NULL, `payloadVersion` INTEGER NOT NULL DEFAULT 1, `payload` LONGTEXT NOT NULL, `idempotencyKey` VARCHAR(191) NOT NULL, `state` VARCHAR(64) NOT NULL DEFAULT 'PENDING', `availableAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), `claimedAt` DATETIME(3) NULL, `claimOwner` VARCHAR(191) NULL, `claimExpiresAt` DATETIME(3) NULL, `attemptCount` INTEGER NOT NULL DEFAULT 0, `maxAttempts` INTEGER NOT NULL DEFAULT 5, `completedAt` DATETIME(3) NULL, `cancelledAt` DATETIME(3) NULL, `failureCode` VARCHAR(191) NULL, `progress` LONGTEXT NOT NULL, `correlationId` VARCHAR(191) NOT NULL, `createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), PRIMARY KEY (`id`), UNIQUE KEY `PrivateContentJob_idempotencyKey_key` (`idempotencyKey`), KEY `PrivateContentJob_state_availableAt_claimExpiresAt_idx` (`state`,`availableAt`,`claimExpiresAt`), CONSTRAINT `PrivateContentJob_operationId_fkey` FOREIGN KEY (`operationId`) REFERENCES `PrivateContentOperation`(`id`) ON DELETE CASCADE);
